import { chromium } from "playwright"
import { execSync } from "node:child_process"

const BASE = "http://localhost:3000"
const SHOT = "/tmp/install-shots"
execSync(`mkdir -p ${SHOT}`)

// DB helper (reads DATABASE_URL from .env)
const DB = execSync(`grep -E '^DATABASE_URL=' .env | sed 's/DATABASE_URL=//; s/\"//g'`).toString().trim()
const q = (sql) =>
  execSync(`psql "${DB}" -tAc ${JSON.stringify(sql)}`).toString().trim()

const log = (...a) => console.log(...a)
const ok = (c, m) => log(`${c ? "✅" : "❌"} ${m}`)

const browser = await chromium.launch()
const ctx = await browser.newContext({ acceptDownloads: true })

// Authenticate via the context request jar (shared with pages)
const signin = await ctx.request.post(`${BASE}/api/auth/sign-in/email`, {
  data: { email: "amy@agentcenter.dev", password: "verify12345" },
})
log("signin status:", signin.status())

const page = await ctx.newPage()
page.on("download", (d) => d.cancel().catch(() => {}))

async function openInstallTab(p) {
  await p.getByRole("tab", { name: /^Install$|^安装$/ }).click()
  await p.waitForTimeout(250)
}

// ---------- 1. skills: render + interpolation (EN) ----------
log("\n=== web-search-pro (skills, EN) ===")
await page.goto(`${BASE}/en/extensions/web-search-pro`, { waitUntil: "networkidle" })
await openInstallTab(page)
await page.screenshot({ path: `${SHOT}/01-skills-conversational.png` })

const triggers = await page.getByRole("tab").allInnerTexts()
log("all tabs visible:", JSON.stringify(triggers))
ok(triggers.includes("Conversational") && triggers.includes("CLI") && triggers.includes("Direct download"),
   "segmented control shows Conversational / CLI / Direct download")

const prompt = (await page.locator("pre").first().innerText()).trim()
log("--- conversational prompt ---\n" + prompt + "\n---")
const expectUrl = `${BASE}/api/v1/extensions/web-search-pro/bundle`
ok(prompt.includes("web-search-pro"), "prompt interpolates slug")
ok(prompt.includes(expectUrl), `prompt has ABSOLUTE bundleUrl (${expectUrl})`)
ok(prompt.includes("~/.claude/skills/web-search-pro"), "prompt has skills destPath")
ok(/\(skills\)/.test(prompt), "prompt has category")

// CLI tab
await page.getByRole("tab", { name: "CLI" }).click()
await page.waitForTimeout(200)
const cli = (await page.locator("pre, code, span").filter({ hasText: "agentcenter install" }).first().innerText()).trim()
log("cli command:", cli)
ok(cli.includes("agentcenter install web-search-pro"), "CLI shows agentcenter install <slug>")

